diff --git a/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp b/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp
index d0b2ded127ff..e10284463c98 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp
@@ -204,6 +204,20 @@ Instruction *InstCombinerImpl::visitMul(BinaryOperator &I) {
   if (Value *V = foldUsingDistributiveLaws(I))
     return replaceInstUsesWith(I, V);

+  // Canonicalize a nested multiply to preserve outer nowrap flags:
+  // (mul nsw/nuw (mul nsw/nuw X, Y), Z) --> (mul (mul Z, Y), X)
+  // This allows the outer multiply to keep its flags while reassociating.
+  Value *InnerX, *InnerY, *OuterZ;
+  if ((I.hasNoSignedWrap() || I.hasNoUnsignedWrap()) &&
+      match(&I, m_Mul(m_OneUse(m_Mul(m_Value(InnerX), m_Value(InnerY))),
+                      m_Value(OuterZ)))) {
+    Value *ZY = Builder.CreateMul(OuterZ, InnerY);
+    BinaryOperator *NewMul = BinaryOperator::CreateMul(ZY, InnerX);
+    NewMul->setHasNoSignedWrap(I.hasNoSignedWrap());
+    NewMul->setHasNoUnsignedWrap(I.hasNoUnsignedWrap());
+    return NewMul;
+  }
+
   Type *Ty = I.getType();
   const unsigned BitWidth = Ty->getScalarSizeInBits();
   const bool HasNSW = I.hasNoSignedWrap();
@@ -344,6 +358,8 @@ Instruction *InstCombinerImpl::visitMul(BinaryOperator &I) {
   // -X * -Y --> X * Y
   if (match(Op0, m_Neg(m_Value(X))) && match(Op1, m_Neg(m_Value(Y)))) {
     auto *NewMul = BinaryOperator::CreateMul(X, Y);
+    if (HasNUW)
+      NewMul->setHasNoUnsignedWrap();
     if (HasNSW && cast<OverflowingBinaryOperator>(Op0)->hasNoSignedWrap() &&
         cast<OverflowingBinaryOperator>(Op1)->hasNoSignedWrap())
       NewMul->setHasNoSignedWrap();

